#include <bits/stdc++.h>
using namespace std;
int main(){
    long long x;
    cin>>x;
    if(x%62==0){
        cout<<"Yes";
        return 0;
    }else if(x>9){
        while(x){
            if(x%100==62){
                cout<<"Yes";
                return 0;
            }
            x/=10;
        }
    }
    cout<<"No";
    return 0;
}
